from flask import Flask, request, jsonify, url_for, render_template_string
from itsdangerous import URLSafeTimedSerializer, BadSignature, SignatureExpired
from werkzeug.security import generate_password_hash, check_password_hash
from dataclasses import dataclass, field
from datetime import datetime, timedelta
import secrets

app = Flask(__name__)
app.config["SECRET_KEY"] = "change-this-secret-key"
app.config["RESET_TOKEN_MAX_AGE_SECONDS"] = 3600

serializer = URLSafeTimedSerializer(app.config["SECRET_KEY"])


@dataclass
class User:
    email: str
    password_hash: str
    mfa_enabled: bool = False
    mfa_secret: str | None = None
    reset_requested_at: datetime | None = None
    reset_token_used: bool = False


users: dict[str, User] = {}


def normalize_email(email: str) -> str:
    return (email or "").strip().lower()


def get_user_by_email(email: str) -> User | None:
    return users.get(normalize_email(email))


def send_email(to_email: str, subject: str, body: str) -> None:
    print(f"--- EMAIL TO: {to_email} ---")
    print(f"SUBJECT: {subject}")
    print(body)
    print("--- END EMAIL ---")


def create_reset_token(email: str) -> str:
    return serializer.dumps({"email": normalize_email(email), "purpose": "mfa-reset"})


def verify_reset_token(token: str, max_age: int) -> str | None:
    try:
        data = serializer.loads(token, max_age=max_age)
        if data.get("purpose") != "mfa-reset":
            return None
        return normalize_email(data.get("email", ""))
    except (BadSignature, SignatureExpired):
        return None


