@app.route("/register", methods=["POST"])
def register():
    data = request.get_json(silent=True) or request.form
    email = normalize_email(data.get("email", ""))
    password = data.get("password", "")

    if not email or not password:
        return jsonify({"error": "email and password required"}), 400
    if email in users:
        return jsonify({"error": "user already exists"}), 409

    users[email] = User(email=email, password_hash=generate_password_hash(password))
    return jsonify({"message": "registered"}), 201


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form
    email = normalize_email(data.get("email", ""))
    password = data.get("password", "")
    mfa_code = data.get("mfa_code", "")

    user = get_user_by_email(email)
    if not user or not check_password_hash(user.password_hash, password):
        return jsonify({"error": "invalid credentials"}), 401

    if user.mfa_enabled:
        if not mfa_code or mfa_code != "123456":
            return jsonify({"error": "mfa required"}), 401

    return jsonify({"message": "login successful", "mfa_enabled": user.mfa_enabled}), 200


@app.route("/mfa/enable", methods=["POST"])
def enable_mfa():
    data = request.get_json(silent=True) or request.form
    email = normalize_email(data.get("email", ""))
    password = data.get("password", "")
    user = get_user_by_email(email)

    if not user or not check_password_hash(user.password_hash, password):
        return jsonify({"error": "invalid credentials"}), 401

    user.mfa_enabled = True
    user.mfa_secret = secrets.token_urlsafe(16)
    return jsonify({"message": "mfa enabled"}), 200


@app.route("/mfa/disable", methods=["POST"])
def disable_mfa():
    data = request.get_json(silent=True) or request.form
    email = normalize_email(data.get("email", ""))
    password = data.get("password", "")
    user = get_user_by_email(email)

    if not user or not check_password_hash(user.password_hash, password):
        return jsonify({"error": "invalid credentials"}), 401

    user.mfa_enabled = False
    user.mfa_secret = None
    return jsonify({"message": "mfa disabled"}), 200


@app.route("/reset-mfa", methods=["POST"])
def reset_mfa_request():
    data = request.get_json(silent=True) or request.form
    email = normalize_email(data.get("email", ""))

    if not email:
        return jsonify({"error": "email required"}), 400

    user = get_user_by_email(email)
    if not user:
        return jsonify({"message": "if the email is registered, a reset link has been sent"}), 200

    token = create_reset_token(user.email)
    reset_link = url_for("reset_mfa_confirm", token=token, _external=True)
    user.reset_requested_at = datetime.utcnow()
    user.reset_token_used = False

    send_email(
        user.email,
        "MFA Reset Request",
        f"Click the link to reset your MFA settings: {reset_link}\n"
        f"This link will disable MFA and allow you to log in with just your password.",
    )

    return jsonify({"message": "if the email is registered, a reset link has been sent"}), 200


@app.route("/reset-mfa/<token>", methods=["GET"])
def reset_mfa_confirm(token):
    email = verify_reset_token(token, app.config["RESET_TOKEN_MAX_AGE_SECONDS"])
    if not email:
        return jsonify({"error": "invalid or expired token"}), 400

    user = get_user_by_email(email)
    if not user:
        return jsonify({"error": "user not found"}), 404

    if user.reset_token_used:
        return jsonify({"error": "token already used"}), 400

    user.mfa_enabled = False
    user.mfa_secret = None
    user.reset_token_used = True
    user.reset_requested_at = None

    return jsonify({"message": "mfa reset successful; you can now log in with password only"}), 200


